package com.taskflow.controller;

import com.taskflow.dto.StatusChangeRequest;
import com.taskflow.dto.TaskPageResponse;
import com.taskflow.dto.TaskRequest;
import com.taskflow.dto.TaskResponse;
import com.taskflow.dto.TransitionResponse;
import com.taskflow.entity.Task;
import com.taskflow.repository.TaskRepository;
import com.taskflow.service.TaskService;
import com.taskflow.service.TaskStateMachine;
import jakarta.validation.Valid;
import org.springframework.data.domain.Pageable;
import org.springframework.data.domain.Sort;
import org.springframework.data.web.PageableDefault;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.DeleteMapping;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PatchMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.PutMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

import java.time.LocalDateTime;
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

@RestController
@RequestMapping("/api/tasks")
public class TaskController {

    private final TaskService taskService;
    private final TaskStateMachine stateMachine;
    private final TaskRepository taskRepository;

    public TaskController(TaskService taskService, TaskStateMachine stateMachine, TaskRepository taskRepository) {
        this.taskService = taskService;
        this.stateMachine = stateMachine;
        this.taskRepository = taskRepository;
    }

    @PostMapping
    public ResponseEntity<TaskResponse> createTask(@Valid @RequestBody TaskRequest request) {
        Long userId = (Long) SecurityContextHolder.getContext().getAuthentication().getPrincipal();
        TaskResponse response = taskService.createTask(userId, request);
        return ResponseEntity.status(HttpStatus.CREATED).body(response);
    }

    @GetMapping("/{id}")
    public ResponseEntity<TaskResponse> getTask(@PathVariable Long id) {
        TaskResponse response = taskService.getTask(id);
        return ResponseEntity.ok(response);
    }

    @PutMapping("/{id}")
    public ResponseEntity<TaskResponse> updateTask(@PathVariable Long id, @Valid @RequestBody TaskRequest request) {
        TaskResponse response = taskService.updateTask(id, request);
        return ResponseEntity.ok(response);
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Void> deleteTask(@PathVariable Long id) {
        taskService.deleteTask(id);
        return ResponseEntity.noContent().build();
    }

    @GetMapping
    public ResponseEntity<TaskPageResponse> listTasks(
            @RequestParam(required = false) String keyword,
            @RequestParam(required = false) Task.Priority priority,
            @RequestParam(required = false) Task.TaskStatus status,
            @PageableDefault(size = 20, sort = "createdAt", direction = Sort.Direction.DESC) Pageable pageable) {
        TaskPageResponse response = taskService.listTasks(keyword, priority, status, pageable);
        return ResponseEntity.ok(response);
    }

    @PatchMapping("/{id}/status")
    public ResponseEntity<?> changeStatus(@PathVariable Long id, @Valid @RequestBody StatusChangeRequest request) {
        Task task = taskRepository.findByIdAndDeletedFalse(id)
                .orElseThrow(() -> new TaskService.TaskNotFoundException("Task not found"));

        if (!stateMachine.canTransition(task.getStatus(), request.getStatus())) {
            return ResponseEntity.badRequest()
                    .body(Map.of("message", "Cannot transition from " + task.getStatus() + " to " + request.getStatus()));
        }

        task.setStatus(request.getStatus());
        task.setUpdatedAt(LocalDateTime.now());
        Task saved = taskRepository.save(task);

        TaskResponse response = new TaskResponse();
        response.setId(saved.getId());
        response.setTitle(saved.getTitle());
        response.setDescription(saved.getDescription());
        response.setPriority(saved.getPriority());
        response.setStatus(saved.getStatus());
        response.setCreatedBy(saved.getCreatedBy());
        response.setCreatedAt(saved.getCreatedAt());
        response.setUpdatedAt(saved.getUpdatedAt());
        return ResponseEntity.ok(response);
    }

    @GetMapping("/{id}/transitions")
    public ResponseEntity<?> getTransitions(@PathVariable Long id) {
        Task task = taskRepository.findByIdAndDeletedFalse(id)
                .orElseThrow(() -> new TaskService.TaskNotFoundException("Task not found"));

        List<String> available = stateMachine.getAvailableTransitions(task.getStatus())
                .stream()
                .map(Enum::name)
                .collect(Collectors.toList());

        TransitionResponse response = new TransitionResponse();
        response.setCurrentStatus(task.getStatus().name());
        response.setAvailableTransitions(available);
        return ResponseEntity.ok(response);
    }

    @ExceptionHandler(TaskService.TaskNotFoundException.class)
    public ResponseEntity<Map<String, String>> handleTaskNotFound(TaskService.TaskNotFoundException ex) {
        return ResponseEntity.status(HttpStatus.NOT_FOUND)
                .body(Map.of("message", ex.getMessage()));
    }

    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ResponseEntity<Map<String, String>> handleValidation(MethodArgumentNotValidException ex) {
        String message = ex.getBindingResult().getFieldErrors().stream()
                .findFirst()
                .map(error -> error.getField() + ": " + error.getDefaultMessage())
                .orElse("Validation failed");
        return ResponseEntity.badRequest()
                .body(Map.of("message", message));
    }
}

