package com.taskflow.service;

import com.taskflow.entity.Task.TaskStatus;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;

import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

class TaskStateMachineTest {

    private TaskStateMachine stateMachine;

    @BeforeEach
    void setUp() {
        stateMachine = new TaskStateMachine();
    }

    // =============================================
    // canTransition — valid transitions
    // =============================================

    @Nested
    class ValidTransitions {

        @Test
        void shouldAllowTodoToInProgress() {
            assertTrue(stateMachine.canTransition(TaskStatus.TODO, TaskStatus.IN_PROGRESS));
        }

        @Test
        void shouldAllowInProgressToTodo() {
            assertTrue(stateMachine.canTransition(TaskStatus.IN_PROGRESS, TaskStatus.TODO));
        }

        @Test
        void shouldAllowInProgressToDone() {
            assertTrue(stateMachine.canTransition(TaskStatus.IN_PROGRESS, TaskStatus.DONE));
        }

        @Test
        void shouldAllowDoneToClosed() {
            assertTrue(stateMachine.canTransition(TaskStatus.DONE, TaskStatus.CLOSED));
        }
    }

    // =============================================
    // canTransition — invalid transitions
    // =============================================

    @Nested
    class InvalidTransitions {

        @Test
        void shouldNotAllowTodoToDone() {
            assertFalse(stateMachine.canTransition(TaskStatus.TODO, TaskStatus.DONE));
        }

        @Test
        void shouldNotAllowTodoToClosed() {
            assertFalse(stateMachine.canTransition(TaskStatus.TODO, TaskStatus.CLOSED));
        }

        @Test
        void shouldNotAllowDoneToTodo() {
            assertFalse(stateMachine.canTransition(TaskStatus.DONE, TaskStatus.TODO));
        }

        @Test
        void shouldNotAllowDoneToInProgress() {
            assertFalse(stateMachine.canTransition(TaskStatus.DONE, TaskStatus.IN_PROGRESS));
        }

        @Test
        void shouldNotAllowClosedToTodo() {
            assertFalse(stateMachine.canTransition(TaskStatus.CLOSED, TaskStatus.TODO));
        }

        @Test
        void shouldNotAllowClosedToInProgress() {
            assertFalse(stateMachine.canTransition(TaskStatus.CLOSED, TaskStatus.IN_PROGRESS));
        }

        @Test
        void shouldNotAllowClosedToDone() {
            assertFalse(stateMachine.canTransition(TaskStatus.CLOSED, TaskStatus.DONE));
        }

        @Test
        void shouldNotAllowSameStatusTransition_todo() {
            assertFalse(stateMachine.canTransition(TaskStatus.TODO, TaskStatus.TODO));
        }

        @Test
        void shouldNotAllowSameStatusTransition_inProgress() {
            assertFalse(stateMachine.canTransition(TaskStatus.IN_PROGRESS, TaskStatus.IN_PROGRESS));
        }

        @Test
        void shouldNotAllowSameStatusTransition_done() {
            assertFalse(stateMachine.canTransition(TaskStatus.DONE, TaskStatus.DONE));
        }

        @Test
        void shouldNotAllowSameStatusTransition_closed() {
            assertFalse(stateMachine.canTransition(TaskStatus.CLOSED, TaskStatus.CLOSED));
        }
    }

    // =============================================
    // getAvailableTransitions
    // =============================================

    @Nested
    class AvailableTransitions {

        @Test
        void shouldReturnInProgressForTodo() {
            List<TaskStatus> transitions = stateMachine.getAvailableTransitions(TaskStatus.TODO);
            assertEquals(1, transitions.size());
            assertTrue(transitions.contains(TaskStatus.IN_PROGRESS));
        }

        @Test
        void shouldReturnTodoAndDoneForInProgress() {
            List<TaskStatus> transitions = stateMachine.getAvailableTransitions(TaskStatus.IN_PROGRESS);
            assertEquals(2, transitions.size());
            assertTrue(transitions.contains(TaskStatus.TODO));
            assertTrue(transitions.contains(TaskStatus.DONE));
        }

        @Test
        void shouldReturnClosedForDone() {
            List<TaskStatus> transitions = stateMachine.getAvailableTransitions(TaskStatus.DONE);
            assertEquals(1, transitions.size());
            assertTrue(transitions.contains(TaskStatus.CLOSED));
        }

        @Test
        void shouldReturnEmptyForClosed() {
            List<TaskStatus> transitions = stateMachine.getAvailableTransitions(TaskStatus.CLOSED);
            assertTrue(transitions.isEmpty());
        }
    }

    // =============================================
    // Terminal state verification
    // =============================================

    @Nested
    class TerminalState {

        @Test
        void closedShouldBeTerminal_noTransitionsAvailable() {
            List<TaskStatus> transitions = stateMachine.getAvailableTransitions(TaskStatus.CLOSED);
            assertTrue(transitions.isEmpty(), "CLOSED is terminal — no transitions should be available");
        }

        @Test
        void closedShouldNotTransitionToAnyState() {
            for (TaskStatus target : TaskStatus.values()) {
                assertFalse(stateMachine.canTransition(TaskStatus.CLOSED, target),
                        "CLOSED should not transition to " + target);
            }
        }
    }
