package com.taskflow.controller;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.taskflow.dto.LoginRequest;
import com.taskflow.dto.RegisterRequest;
import com.taskflow.repository.TaskRepository;
import com.taskflow.repository.UserRepository;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;
import org.springframework.test.web.servlet.MvcResult;
import org.springframework.transaction.annotation.Transactional;

import static org.hamcrest.Matchers.*;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

@SpringBootTest
@AutoConfigureMockMvc
@Transactional
class StatusTransitionIntegrationTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private TaskRepository taskRepository;

    private String authToken;

    @BeforeEach
    void setUp() throws Exception {
        taskRepository.deleteAll();
        userRepository.deleteAll();

        RegisterRequest reg = new RegisterRequest();
        reg.setUsername("stateuser");
        reg.setPassword("password123");
        reg.setDisplayName("State User");

        mockMvc.perform(post("/api/auth/register")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(reg)))
                .andExpect(status().isCreated());

        LoginRequest login = new LoginRequest();
        login.setUsername("stateuser");
        login.setPassword("password123");

        MvcResult loginResult = mockMvc.perform(post("/api/auth/login")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(login)))
                .andExpect(status().isOk())
                .andReturn();

        JsonNode loginJson = objectMapper.readTree(loginResult.getResponse().getContentAsString());
        authToken = loginJson.get("token").asText();
    }

    // ========== Helper Methods ==========

    private Long createTask(String title) throws Exception {
        String json = "{\"title\":\"" + title + "\"}";
        MvcResult result = mockMvc.perform(post("/api/tasks")
                        .header("Authorization", "Bearer " + authToken)
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(json))
                .andExpect(status().isCreated())
                .andReturn();
        return objectMapper.readTree(result.getResponse().getContentAsString()).get("id").asLong();
    }

    private MvcResult changeStatus(Long taskId, String targetStatus) throws Exception {
        String json = "{\"status\":\"" + targetStatus + "\"}";
        return mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
                        .header("Authorization", "Bearer " + authToken)
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(json))
                .andReturn();
    }

    private void changeStatusExpect200(Long taskId, String targetStatus) throws Exception {
        String json = "{\"status\":\"" + targetStatus + "\"}";
        mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
                        .header("Authorization", "Bearer " + authToken)
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(json))
                .andExpect(status().isOk());
    }

    // =============================================
    // AC1: New task defaults to TODO
    // =============================================

    @Nested
    class NewTaskStatus {

        @Test
        void ac1_newTaskShouldHaveStatusTodo() throws Exception {
            MvcResult result = mockMvc.perform(post("/api/tasks")
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content("{\"title\":\"New Task\"}"))
                    .andExpect(status().isCreated())
                    .andExpect(jsonPath("$.status").value("TODO"))
                    .andReturn();
        }
    }

    // =============================================
    // AC2-AC5: Valid transitions
    // =============================================

    @Nested
    class ValidTransitions {

        // AC2: TODO -> IN_PROGRESS
        @Test
        void ac2_shouldTransitionFromTodoToInProgress() throws Exception {
            Long taskId = createTask("AC2 Task");

            mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content("{\"status\":\"IN_PROGRESS\"}"))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.status").value("IN_PROGRESS"))
                    .andExpect(jsonPath("$.id").value(taskId));
        }

        // AC3: IN_PROGRESS -> TODO
        @Test
        void ac3_shouldTransitionFromInProgressToTodo() throws Exception {
            Long taskId = createTask("AC3 Task");
            changeStatusExpect200(taskId, "IN_PROGRESS");

            mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
